---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ServiceTimes from '../components/ServiceTimes.astro';
import ImageMosaic from '../components/ImageMosaic.astro';
import Pillars from '../components/Pillars.astro';
import Card from '../components/Card.astro';
import NextSteps from '../components/NextSteps.astro';
import { getHomePage, getSermons, getEvents, urlForImage } from '../lib/sanity';

const title = 'First Ithaca Chinese Christian Church | 伊的家華人基督教會';
const description =
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY. Sunday gathering at 9:45am, 429 Mitchell Street.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let homePage: Awaited<ReturnType<typeof getHomePage>> = null;
let sermons: Awaited<ReturnType<typeof getSermons>> = [];
let events: Awaited<ReturnType<typeof getEvents>> = [];

try {
  [homePage, sermons, events] = await Promise.all([
    getHomePage('en'),
    getSermons('en'),
    getEvents('en'),
  ]);
} catch {
  // Sanity unreachable (placeholder project, no network, etc.) — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackServiceTimes = [
  { label: 'Sunday Gathering', time: '9:45 AM' },
  { label: 'Sunday School', time: '11:15 AM' },
];

const fallbackPillars = [
  {
    title: 'Rooted in Scripture',
    description:
      "We hold to the Bible as God's inspired Word and the foundation for all of life and faith.",
  },
  {
    title: 'Christ-Centered Community',
    description:
      'We gather as a Christ-centered community, welcoming students, families, and neighbors of all backgrounds.',
  },
  {
    title: 'Bridging Cultures',
    description:
      'We celebrate our Chinese heritage while building a church home that bridges cultures and generations.',
  },
];

const fallbackNextSteps = [
  {
    title: 'Plan Your Visit',
    body: 'Join us Sunday at 9:45 AM. Learn what to expect and how to find us.',
    href: '/visit',
  },
  {
    title: 'Get Connected',
    body: 'Discover small groups, ministries, and ways to grow alongside others.',
    href: '/ministries',
  },
  {
    title: 'Watch Sermons',
    body: 'Catch up on recent messages or explore a teaching series.',
    href: '/sermons',
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = homePage?.heroImage
  ? urlForImage(homePage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = homePage?.heroTitle || 'Welcome Home';
const heroSubtitle =
  homePage?.heroSubtitle ||
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.';
const heroCtaText = homePage?.heroCtaText || 'Plan Your Visit';
const heroCtaHref = homePage?.heroCtaHref || '/visit';

const serviceTimes =
  homePage?.serviceTimes && homePage.serviceTimes.length > 0
    ? homePage.serviceTimes
    : fallbackServiceTimes;

const mosaicImages =
  homePage?.mosaicImages && homePage.mosaicImages.length > 0
    ? homePage.mosaicImages.map((img) => ({
        src: urlForImage(img, { width: 800 }),
        alt: img.alt || '',
      }))
    : Array.from({ length: 6 }, (_, i) => ({
        src: `/images/placeholder-${i + 1}.svg`,
        alt: `Church life ${i + 1}`,
      }));

const pillars =
  homePage?.pillars && homePage.pillars.length > 0
    ? homePage.pillars.map((p) => ({
        title: p.title,
        description: p.description || '',
      }))
    : fallbackPillars;

const nextSteps =
  homePage?.nextSteps && homePage.nextSteps.length > 0
    ? homePage.nextSteps.map((s) => ({
        title: s.title,
        body: s.body || '',
        href: s.href || '#',
        image: s.image ? urlForImage(s.image, { width: 600 }) : undefined,
      }))
    : fallbackNextSteps;

// ---------- Featured content ----------
const latestSermon = sermons[0] ?? null;
const nextEvent = events[0] ?? null;
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      ctaText={heroCtaText}
      ctaHref={heroCtaHref}
      backgroundImage={heroImage}
    />

    <ServiceTimes times={serviceTimes} />

    <section class="mosaic-section" aria-label="Church Life">
      <div class="mosaic-section__inner">
        <ImageMosaic images={mosaicImages} />
      </div>
    </section>

    <Pillars pillars={pillars} />

    {(latestSermon || nextEvent) && (
      <section class="featured" aria-label="Featured">
        <div class="featured__inner">
          <h2 class="featured__heading">Stay Connected</h2>
          <div class="featured__grid">
            {latestSermon && (
              <Card
                title={latestSermon.title}
                body={latestSermon.speaker ? `Speaker: ${latestSermon.speaker}` : 'Latest sermon'}
                href="/sermons"
              />
            )}
            {nextEvent && (
              <Card
                title={nextEvent.title}
                body={nextEvent.date ? `Date: ${nextEvent.date}` : 'Upcoming event'}
                href="/events"
              />
            )}
          </div>
        </div>
      </section>
    )}

    <NextSteps steps={nextSteps} />
  </main>
</BaseLayout>

<style>
  .mosaic-section {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .mosaic-section__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .featured__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-12);
  }

  .featured__grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-8);
  }

  @media (max-width: 768px) {
    .featured__grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .featured__heading {
      font-size: var(--text-2xl);
    }
  }
</style>

import { createClient } from '@sanity/client';

const projectId = import.meta.env.SANITY_PROJECT_ID || 'placeholder';
const dataset = import.meta.env.SANITY_DATASET || 'production';

export const client = createClient({
  projectId,
  dataset,
  apiVersion: '2026-03-31',
  useCdn: true,
});

export { projectId, dataset };

// ---------------------------------------------------------------------------
// Shared types — lightweight interfaces matching schema shapes.
// Full Sanity-generated types can replace these later.
// ---------------------------------------------------------------------------

export interface SanitySlug {
  _type: 'slug';
  current: string;
}

export interface PortableTextBlock {
  _type: string;
  _key: string;
  [key: string]: unknown;
}

export interface SanityImage {
  _type: 'image';
  asset: { _ref: string; _type: 'reference' };
}

export interface Page {
  _id: string;
  _type: 'page';
  title: string;
  slug: SanitySlug;
  body: PortableTextBlock[];
  language: 'en' | 'zh';
}

export interface Sermon {
  _id: string;
  _type: 'sermon';
  title: string;
  slug?: SanitySlug;
  speaker?: string;
  date?: string;
  series?: string;
  scripture?: string;
  videoId?: string;
  language: 'en' | 'zh';
}

export interface Event {
  _id: string;
  _type: 'event';
  title: string;
  date?: string;
  endDate?: string;
  time?: string;
  location?: string;
  description?: PortableTextBlock[];
  image?: SanityImage;
  recurring?: boolean;
  language: 'en' | 'zh';
}

export interface Ministry {
  _id: string;
  _type: 'ministry';
  name: string;
  slug?: SanitySlug;
  image?: SanityImage;
  description?: PortableTextBlock[];
  leader?: { _ref: string };
  meetingTime?: string;
  language: 'en' | 'zh';
}

/** Ministry with leader reference resolved inline (for detail pages). */
export interface MinistryDetail extends Omit<Ministry, 'leader'> {
  leader?: {
    name: string;
    role?: string;
    photo?: SanityImage;
  } | null;
}

export interface SocialLink {
  platform: string;
  url: string;
}

export interface SiteSettings {
  _id: string;
  _type: 'siteSettings';
  churchName: string;
  address?: string;
  phone?: string;
  email?: string;
  socialLinks?: SocialLink[];
  language: 'en' | 'zh';
}

export interface NavChild {
  label: string;
  href?: string;
}

export interface NavItem {
  label: string;
  href?: string;
  children?: NavChild[];
}

export interface Navigation {
  _id: string;
  _type: 'navigation';
  navItems: NavItem[];
  language: 'en' | 'zh';
}

export interface ServiceTime {
  label: string;
  time: string;
}

export interface Pillar {
  title: string;
  description?: string;
}

export interface NextStep {
  title: string;
  body?: string;
  href?: string;
  image?: SanityImage;
}

export interface MosaicImage extends SanityImage {
  alt?: string;
}

export interface HomePage {
  _id: string;
  _type: 'homePage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  heroCtaText?: string;
  heroCtaHref?: string;
  serviceTimes?: ServiceTime[];
  mosaicImages?: MosaicImage[];
  pillars?: Pillar[];
  nextSteps?: NextStep[];
  language: 'en' | 'zh';
}

export interface BeliefItem {
  _key: string;
  title: string;
  content?: PortableTextBlock[];
}

export interface AboutPage {
  _id: string;
  _type: 'aboutPage';
  whoWeAreHeading?: string;
  whoWeAreBody?: PortableTextBlock[];
  whoWeAreImage?: SanityImage;
  visionHeading?: string;
  visionBody?: PortableTextBlock[];
  churchStats?: { value: string; label: string }[];
  beliefs?: BeliefItem[];
  staffOrder?: { _ref: string }[];
  language: 'en' | 'zh';
}

export interface ScheduleItem {
  label: string;
  time: string;
  description?: string;
}

export interface FaqItem {
  question: string;
  answer: string;
}

export interface VisitPage {
  _id: string;
  _type: 'visitPage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  whatToExpect?: PortableTextBlock[];
  schedule?: ScheduleItem[];
  transportation?: PortableTextBlock[];
  faqItems?: FaqItem[];
  rideRequestEnabled?: boolean;
  language: 'en' | 'zh';
}

export interface ResourceItem {
  title: string;
  url?: string;
  description?: string;
  type?: 'article' | 'pdf' | 'link';
}

export interface ResourceCategory {
  title: string;
  description?: string;
  resources?: ResourceItem[];
}

export interface ResourcesPage {
  _id: string;
  _type: 'resourcesPage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  resourceCategories?: ResourceCategory[];
  language: 'en' | 'zh';
}

export interface Person {
  _id: string;
  _type: 'person';
  name: string;
  role?: string;
  bio?: PortableTextBlock[];
  photo?: SanityImage;
  language: 'en' | 'zh';
}

// ---------------------------------------------------------------------------
// GROQ query helpers
// ---------------------------------------------------------------------------

type Language = 'en' | 'zh';

/**
 * Fetch a page by its slug and language.
 */
export async function getPageBySlug(
  slug: string,
  language: Language = 'en',
): Promise<Page | null> {
  return client.fetch<Page | null>(
    `*[_type == "page" && slug.current == $slug && language == $language][0]`,
    { slug, language },
  );
}

/**
 * Fetch all sermons for a language, newest first.
 */
export async function getSermons(language: Language = 'en'): Promise<Sermon[]> {
  return client.fetch<Sermon[]>(
    `*[_type == "sermon" && language == $language]{
      _id, _type, title, slug, speaker, date, series, scripture, videoId, language
    } | order(date desc)`,
    { language },
  );
}

/**
 * Fetch a single sermon by its slug and language.
 */
export async function getSermonBySlug(
  slug: string,
  language: Language = 'en',
): Promise<Sermon | null> {
  return client.fetch<Sermon | null>(
    `*[_type == "sermon" && slug.current == $slug && language == $language][0]`,
    { slug, language },
  );
}

/**
 * Fetch upcoming events for a language, soonest first.
 */
export async function getEvents(language: Language = 'en'): Promise<Event[]> {
  return client.fetch<Event[]>(
    `*[_type == "event" && language == $language]{
      _id, _type, title, date, endDate, time, location, description, image, recurring, language
    } | order(date asc)`,
    { language },
  );
}

/**
 * Fetch all ministries for a language.
 */
export async function getMinistries(
  language: Language = 'en',
): Promise<Ministry[]> {
  return client.fetch<Ministry[]>(
    `*[_type == "ministry" && language == $language] | order(name asc)`,
    { language },
  );
}

/**
 * Fetch a single ministry by slug with leader reference resolved.
 */
export async function getMinistryBySlug(
  slug: string,
  language: Language = 'en',
): Promise<MinistryDetail | null> {
  return client.fetch<MinistryDetail | null>(
    `*[_type == "ministry" && slug.current == $slug && language == $language][0]{
      _id, _type, name, slug, image, description, meetingTime, language,
      leader->{name, role, photo}
    }`,
    { slug, language },
  );
}

/**
 * Fetch the singleton site-settings document for a language.
 * Singleton IDs follow the pattern `{type}-{lang}` per D-decision.
 */
export async function getSiteSettings(
  language: Language = 'en',
): Promise<SiteSettings | null> {
  return client.fetch<SiteSettings | null>(
    `*[_type == "siteSettings" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton navigation document for a language.
 */
export async function getNavigation(
  language: Language = 'en',
): Promise<Navigation | null> {
  return client.fetch<Navigation | null>(
    `*[_type == "navigation" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton home-page document for a language.
 */
export async function getHomePage(
  language: Language = 'en',
): Promise<HomePage | null> {
  return client.fetch<HomePage | null>(
    `*[_type == "homePage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton about-page document for a language.
 */
export async function getAboutPage(
  language: Language = 'en',
): Promise<AboutPage | null> {
  return client.fetch<AboutPage | null>(
    `*[_type == "aboutPage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton visit-page document for a language.
 */
export async function getVisitPage(
  language: Language = 'en',
): Promise<VisitPage | null> {
  return client.fetch<VisitPage | null>(
    `*[_type == "visitPage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton resources-page document for a language.
 */
export async function getResourcesPage(
  language: Language = 'en',
): Promise<ResourcesPage | null> {
  return client.fetch<ResourcesPage | null>(
    `*[_type == "resourcesPage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch person documents for a language, ordered by name.
 */
export async function getStaff(
  language: Language = 'en',
): Promise<Person[]> {
  return client.fetch<Person[]>(
    `*[_type == "person" && language == $language] | order(name asc)`,
    { language },
  );
}

// ---------------------------------------------------------------------------
// Image helpers
// ---------------------------------------------------------------------------

/**
 * Resolve a Sanity image asset reference to a CDN URL.
 *
 * Asset refs look like `image-<id>-<WxH>-<ext>`. We strip the `image-`
 * prefix and replace the last `-` (before the extension) with `.` to get
 * the filename portion used in the CDN path.
 *
 * Example ref: `image-abc123-800x600-jpg`
 * Result:      `https://cdn.sanity.io/images/{projectId}/{dataset}/abc123-800x600.jpg`
 */
export function urlForImage(
  image: SanityImage | undefined | null,
  options?: { width?: number; format?: string },
): string {
  if (!image?.asset?._ref) return '';

  const ref = image.asset._ref;
  // Strip leading "image-" and split on the last "-" to get id and extension
  const withoutPrefix = ref.replace(/^image-/, '');
  const lastDash = withoutPrefix.lastIndexOf('-');
  if (lastDash === -1) return '';

  const idAndDimensions = withoutPrefix.slice(0, lastDash);
  const ext = withoutPrefix.slice(lastDash + 1);
  const filename = `${idAndDimensions}.${ext}`;

  let url = `https://cdn.sanity.io/images/${projectId}/${dataset}/${filename}`;

  const params = new URLSearchParams();
  if (options?.width) params.set('w', String(options.width));
  if (options?.format) params.set('fm', options.format);
  const qs = params.toString();
  if (qs) url += `?${qs}`;

  return url;
}

// ---------------------------------------------------------------------------
// Portable Text → HTML (lightweight server-side renderer)
// ---------------------------------------------------------------------------

/**
 * Convert an array of Portable Text blocks to an HTML string.
 *
 * Handles `block` type with `normal` style (paragraphs), `strong`/`em` marks,
 * and `link` annotations. Other block types are silently skipped.
 */
export function portableTextToHtml(blocks: PortableTextBlock[] | undefined | null): string {
  if (!blocks?.length) return '';

  return blocks
    .filter((b) => b._type === 'block')
    .map((block) => {
      const children = (block.children as Array<{
        _type: string;
        text: string;
        marks?: string[];
      }>) || [];

      const markDefs = (block.markDefs as Array<{
        _key: string;
        _type: string;
        href?: string;
      }>) || [];

      const inner = children
        .map((child) => {
          let text = escapeHtml(child.text || '');
          if (!child.marks?.length) return text;

          for (const mark of child.marks) {
            if (mark === 'strong') {
              text = `<strong>${text}</strong>`;
            } else if (mark === 'em') {
              text = `<em>${text}</em>`;
            } else {
              // Check markDefs for link annotations
              const def = markDefs.find((d) => d._key === mark);
              if (def?._type === 'link' && def.href) {
                text = `<a href="${escapeHtml(def.href)}">${text}</a>`;
              }
            }
          }
          return text;
        })
        .join('');

      return `<p>${inner}</p>`;
    })
    .join('\n');
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ---------------------------------------------------------------------------
// Visual Editing — draft-aware query helper for server-rendered preview
// ---------------------------------------------------------------------------

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';

/**
 * Draft-aware query helper for preview/visual-editing contexts.
 *
 * When `PUBLIC_SANITY_VISUAL_EDITING_ENABLED` is `'true'`:
 *   - Uses `perspective: 'previewDrafts'` so editors see unpublished changes
 *   - Injects `SANITY_API_READ_TOKEN` (server-only) for authenticated draft access
 *   - Enables stega encoding and result source maps for click-to-edit overlays
 *
 * When disabled, falls back to published perspective with no token or stega.
 *
 * This is a *parallel* helper — existing getPageBySlug / getSermons / etc.
 * remain unchanged for static build-time fetching.
 */
export async function loadQuery<T = unknown>(
  query: string,
  params: Record<string, unknown> = {},
): Promise<{ data: T }> {
  if (isVisualEditingEnabled) {
    const token = import.meta.env.SANITY_API_READ_TOKEN;
    if (!token) {
      throw new Error(
        '[sanity/loadQuery] PUBLIC_SANITY_VISUAL_EDITING_ENABLED is true but ' +
          'SANITY_API_READ_TOKEN is not set. Add the token to your environment ' +
          '(server-only, no PUBLIC_ prefix).',
      );
    }

    if (import.meta.env.DEV) {
      console.debug('[sanity/loadQuery] perspective: previewDrafts (visual editing enabled)');
    }

    const data = await client.fetch<T>(query, params, {
      perspective: 'previewDrafts',
      stega: true,
      token,
      resultSourceMap: true,
    });
    return { data };
  }

  const data = await client.fetch<T>(query, params, {
    perspective: 'published',
  });
  return { data };
}

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { getAboutPage, portableTextToHtml, urlForImage } from '../../lib/sanity';

const title = 'Who We Are | FICCC';
const description =
  'Learn about First Ithaca Chinese Christian Church — our history, mission, and community.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackHeading = 'Who We Are';
const fallbackBody = `
<p>First Ithaca Chinese Christian Church (FICCC) was founded in 1968 by a small group of Chinese graduate students and scholars at Cornell University who longed for a Christ-centered community where they could worship in their heart language while welcoming the broader Ithaca community.</p>
<p>Over the decades the church has grown into a multigenerational, multicultural congregation that bridges Chinese heritage and American life. We gather every Sunday at 429 Mitchell Street for worship, teaching, and fellowship — in English and Mandarin — serving students, families, and neighbors throughout the Finger Lakes region.</p>
<p>Our mission is to glorify God by making disciples of Jesus Christ who love God wholeheartedly, love one another sacrificially, and reach out to the world with the Gospel. We believe the local church is God's primary instrument for advancing His kingdom, and we are committed to equipping every member for a life of faithful service.</p>
<p>Whether you are a longtime resident of Ithaca, a visiting scholar, or a student far from home, there is a place for you at FICCC. We invite you to come as you are and experience the warmth of Christ's love in community.</p>
`.trim();

const fallbackVisionHeading = 'Our Vision';
const fallbackVisionHtml = `
<p><strong>Develop Humble Servants Who Love the Lord, Love the Lost, Love the Local Church — For the Rest of Their Lives.</strong></p>
<p>Most of the students and scholars who walk through our doors will only be in Ithaca for a few years. But we believe that what happens during those years — the habits of worship, the depth of community, the encounters with Scripture — can shape the trajectory of an entire life.</p>
<p>Our vision is to nurture Christ-followers who don't just "do church" while they're here, but who carry the marks of discipleship wherever they go: into careers, families, churches, and communities around the world.</p>
`.trim();

const fallbackStats = [
  { value: '~150', label: 'Congregation Members' },
  { value: '~20', label: 'Baptisms Per Year' },
  { value: '18', label: 'Full-Time Ministers Sent' },
  { value: '40+', label: 'Years in Ithaca' },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heading = aboutPage?.whoWeAreHeading || fallbackHeading;
const bodyHtml = aboutPage?.whoWeAreBody?.length
  ? portableTextToHtml(aboutPage.whoWeAreBody)
  : fallbackBody;
const imageUrl = aboutPage?.whoWeAreImage
  ? urlForImage(aboutPage.whoWeAreImage, { width: 800 })
  : '';

const visionHeading = aboutPage?.visionHeading || fallbackVisionHeading;
const visionHtml = aboutPage?.visionBody?.length
  ? portableTextToHtml(aboutPage.visionBody)
  : fallbackVisionHtml;

const stats =
  aboutPage?.churchStats && aboutPage.churchStats.length > 0
    ? aboutPage.churchStats
    : fallbackStats;
---

<BaseLayout title={title} description={description}>
  <main class="about">
    <section class="about__hero" aria-label="Who We Are">
      <div class="about__inner">
        <h1 class="about__heading">{heading}</h1>
        <div class="about__content">
          <div class="about__body" set:html={bodyHtml} />
          {imageUrl && (
            <div class="about__image-wrap">
              <img
                class="about__image"
                src={imageUrl}
                alt={heading}
                loading="lazy"
                width="800"
                height="533"
              />
            </div>
          )}
        </div>
      </div>
    </section>

    <!-- Vision Statement -->
    <section class="vision" aria-label="Our Vision">
      <div class="vision__inner">
        <h2 class="vision__heading">{visionHeading}</h2>
        <div class="vision__body" set:html={visionHtml} />
      </div>
